import torch
from torchvision import transforms, datasets
from torch.utils.data import DataLoader

# Function to download and load a pretrained model from a URL
def load_pretrained_model(model_url):
    # Download the model checkpoint
    model_checkpoint = torch.hub.load_state_dict_from_url(model_url)
    
    # Assuming the model is a simple classification model
    model = torchvision.models.resnet18(pretrained=False)  # Example model, replace with actual model class
    model.load_state_dict(model_checkpoint)
    
    return model

# Function to fine-tune the model on a custom dataset
def fine_tune_model(model, train_loader, val_loader, num_epochs=10, learning_rate=0.001):
    # Move model to GPU if available
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    model.to(device)
    
    # Define loss function and optimizer
    criterion = torch.nn.CrossEntropyLoss()
    optimizer = torch.optim.Adam(model.parameters(), lr=learning_rate)
    
    # Training loop
    for epoch in range(num_epochs):
        model.train()
        running_loss = 0.0
        
        for inputs, labels in train_loader:
            inputs, labels = inputs.to(device), labels.to(device)
            
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            
            running_loss += loss.item() * inputs.size(0)
        
        epoch_loss = running_loss / len(train_loader.dataset)
        print(f'Epoch {epoch+1}/{num_epochs}, Loss: {epoch_loss:.4f}')
        
        # Validation
        model.eval()
        correct = 0
        total = 0
        
        with torch.no_grad():
            for inputs, labels in val_loader:
                inputs, labels = inputs.to(device), labels.to(device)
                
                outputs = model(inputs)
                _, predicted = torch.max(outputs.data, 1)
                total += labels.size(0)
                correct += (predicted == labels).sum().item()
        
        accuracy = 100 * correct / total
        print(f'Validation Accuracy: {accuracy:.2f}%')
    
    return model

# Example usage
if __name__ == "__main__":
    # URL of the pretrained model checkpoint
    model_url = 'https://example.com/path/to/model_checkpoint.pth'
    
    # Load the pretrained model
    model = load_pretrained_model(model_url)
    
    # Define transformations for the dataset
    transform = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
    ])
    
    # Load custom dataset
    train_dataset = datasets.ImageFolder(root='path/to/train', transform=transform)
    val_dataset = datasets.ImageFolder(root='path/to/val', transform=transform)
    
    # Create data loaders
    train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)
    val_loader = DataLoader(val_dataset, batch_size=32, shuffle=False)
    
    # Fine-tune the model
    fine_tuned_model = fine_tune_model(model, train_loader, val_loader)